package Inheritance;

/*
 * ============================================================
 * 2) MULTILEVEL INHERITANCE  (a chain: A -> B -> C)
 * ============================================================
 * A class can inherit from a class that itself inherits from another.
 * This is still SINGLE inheritance at each level - and it IS allowed.
 *
 *   LivingThing  ->  Creature  ->  Cat
 */

class LivingThing {
    void breathe() {
        System.out.println("Breathing...");
    }
}

class Creature extends LivingThing {
    void move() {
        System.out.println("Moving...");
    }
}

class Cat extends Creature {
    void meow() {
        System.out.println("Meow!");
    }
}

public class MultilevelInheritance {
    public static void main(String[] args) {
        Cat c = new Cat();
        c.breathe(); // from LivingThing  (grandparent)
        c.move();    // from Creature     (parent)
        c.meow();    // from Cat          (itself)
    }
}

package Inheritance;

/*
 * ============================================================
 * 1) SINGLE INHERITANCE  (one child extends one parent)
 * ============================================================
 * Java supports SINGLE class inheritance using the "extends" keyword.
 * A subclass inherits fields and methods from its superclass.
 */

// Parent / Super class
class Animal {
    String name;

    Animal(String name) {
        this.name = name;
    }

    void eat() {
        System.out.println(name + " is eating.");
    }

    void sleep() {
        System.out.println(name + " is sleeping.");
    }
}

// Child / Sub class -> inherits from Animal
class Dog extends Animal {

    Dog(String name) {
        super(name); // call parent constructor
    }

    // Dog-specific behaviour
    void bark() {
        System.out.println(name + " says: Woof!");
    }
}

public class SingleInheritance {
    public static void main(String[] args) {
        Dog d = new Dog("Rex");
        d.eat();   // inherited from Animal
        d.sleep(); // inherited from Animal
        d.bark();  // defined in Dog
    }
}

package Inheritance;
/* * ============================================================ * 3) WHY JAVA DOES NOT ALLOW MULTIPLE *CLASS* INHERITANCE * ============================================================ * * The DIAMOND PROBLEM: * * A (method greet()) * / \ * B C (both override greet()) * \ / * D <-- if D could extend B AND C, * which greet() should it use? AMBIGUOUS! * * To avoid this confusion, Java FORBIDS a class extending more than one class. * * class D extends B, C { } // <-- COMPILE ERROR, not allowed in Java * * Other languages like C++ allow it but must add extra rules to resolve * the ambiguity. Java keeps things simple by disallowing it for classes. * * SOLUTION in Java: use INTERFACES (see MultipleInheritanceWithInterfaces.java) */
public class WhyNoMultipleClassInheritance { public static void main(String[] args) { System.out.println("A Java class can extend ONLY ONE class."); System.out.println("Use interfaces to gain 'multiple inheritance' of type."); } }
